#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e3+5;
int n,a[N],s[N],dp[N][N];
int min(int x,int y){return (x<y?x:y);}
int max(int x,int y){return (x>y?x:y);}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read();
    for(int i=n;i>=1;i--)a[i]=read();
    for(int i=1;i<=n;i++)s[i]=s[i-1]+a[i];
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            dp[i][j]=dp[i][j-1];int k=j*2-1;
            if(k<=i)dp[i][j]=max(dp[i][j],s[i]-dp[i-k][k]);
            k++;if(k<=i)dp[i][j]=max(dp[i][j],s[i]-dp[i-k][k]);
        }
    cout<<dp[n][1]<<"\n";
    return 0;
}
